generated_oml:
// C3: Physical sensing components
instance MotorMountedEncoder : DTDFVocab:SensingComponent [
    base:desc "Motor‑mounted encoder providing position measurements for the permanent‑magnet synchronous motor"
    DTDFVocab:producedData MotorMountedEncoderDataTransmitted
]

instance GearboxSecondaryEncoder : DTDFVocab:SensingComponent [
    base:desc "Secondary encoder located behind the gearwheel gearbox providing position measurements"
    DTDFVocab:producedData GearboxSecondaryEncoderDataTransmitted
]

instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Current sensor measuring the input current I_M of the motor"
    DTDFVocab:producedData MotorCurrentDataTransmitted
]

instance OutputAngleSensor : DTDFVocab:SensingComponent [
    base:desc "Sensor measuring the output angle of the cycloidal gearbox"
    DTDFVocab:producedData OutputAngleDataTransmitted
]

// C4: Physical‑to‑virtual interaction (DataTransmitted)
instance MotorMountedEncoderDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorMountedEncoder
]

instance GearboxSecondaryEncoderDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxSecondaryEncoder
]

instance MotorCurrentDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

instance OutputAngleDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom OutputAngleSensor
]

// C10: Data (traces)
instance MotorEncoderData : DTDFVocab:Data [
    base:desc "Time‑series of motor encoder positions transmitted via MQTT"
    DTDFVocab:fromData MotorMountedEncoderDataTransmitted
    DTDFVocab:inputTo DataProcessingEngine
]

instance GearboxEncoderData : DTDFVocab:Data [
    base:desc "Time‑series of gearbox secondary encoder positions transmitted via MQTT"
    DTDFVocab:fromData GearboxSecondaryEncoderDataTransmitted
    DTDFVocab:inputTo DataProcessingEngine
]

instance MotorCurrentData : DTDFVocab:Data [
    base:desc "Time‑series of motor input current I_M transmitted via MQTT"
    DTDFVocab:fromData MotorCurrentDataTransmitted
    DTDFVocab:inputTo DataProcessingEngine
]

instance OutputAngleData : DTDFVocab:Data [
    base:desc "Time‑series of gearbox output angle transmitted via MQTT"
    DTDFVocab:fromData OutputAngleDataTransmitted
    DTDFVocab:inputTo DataProcessingEngine
]

// C11: Enablers
instance MQTTBrokerEnabler : DTDFVocab:Enabler [
    base:desc "MQTT broker enabling real‑time streaming of sensor data to the digital shadow"
]

instance DataProcessingEngine : DTDFVocab:Enabler [
    base:desc "Processing component that consumes sensor traces, runs friction identification algorithms and produces output traces"
    DTDFVocab:enables IdentificationService, ModelUpdateService
]

instance SimulinkSimulationEngine : DTDFVocab:Enabler [
    base:desc "MathWorks Simulink execution environment for friction‑free and friction models (Coulomb‑Viscous, Stribeck, Dahl, LuGre)"
    DTDFVocab:enables ModelUpdateService
]

instance DashboardEngine : DTDFVocab:Enabler [
    base:desc "Custom dashboard visualizing measured and simulated data and allowing operator interaction"
    DTDFVocab:enables DashboardService
]

// C10: Models/Data
instance SysMLStructuralModel : DTDFVocab:Model [
    base:desc "SysML Block Definition and Internal Block Diagrams describing motor, gearwheel and cycloidal gearbox components and their rotational and current flows"
    DTDFVocab:inputTo SimulinkSimulationEngine
]

instance SimulinkFrictionModelSet : DTDFVocab:Model [
    base:desc "Simulink models implementing friction‑free and several friction models (Coulomb‑Viscous, Stribeck, Dahl, LuGre)"
    DTDFVocab:inputTo SimulinkSimulationEngine
]

// C6: Services
instance IdentificationService : DTDFVocab:Service [
    base:desc "Continuously identifies static, kinetic and viscous friction parameters from processed sensor data"
    DTDFVocab:provides FrictionParameterInsight
]

instance ModelUpdateService : DTDFVocab:Service [
    base:desc "Updates analytical (white‑box) and data‑driven (black‑box) friction models with identified parameters"
    DTDFVocab:provides UpdateFrictionModelsAction, UpdateRobotControllerAction
]

instance MotionControlParameterService : DTDFVocab:Service [
    base:desc "Provides improved motion‑control parameters to the robot controller based on the latest friction identification"
    DTDFVocab:provides UpdateRobotControllerAction
]

instance DashboardService : DTDFVocab:Service [
    base:desc "Visualizes measured and simulated data, supports operator interaction and triggers refinement actions"
    DTDFVocab:provides MotionAccuracyInsight, RefineDigitalShadowAction
]

// C17: Insights
instance FrictionParameterInsight : DTDFVocab:Insight [
    base:desc "Derived friction parameters (static, kinetic, viscous) for the cycloidal gearbox"
]

instance MotionAccuracyInsight : DTDFVocab:Insight [
    base:desc "Improved motion accuracy and reduced positioning errors achieved by updating control parameters"
]

// C17: Actions
instance UpdateFrictionModelsAction : DTDFVocab:Action [
    base:desc "Updates analytical and data‑driven friction models with newly identified parameters"
    DTDFVocab:IsAutomatic true
]

instance UpdateRobotControllerAction : DTDFVocab:Action [
    base:desc "Feeds back friction parameters to the robot controller to improve motion control"
    DTDFVocab:IsAutomatic true
]

instance RefineDigitalShadowAction : DTDFVocab:Action [
    base:desc "Iteratively refines the digital shadow as new sensor data become available"
    DTDFVocab:IsAutomatic false
]

// C5: Component (system under study)
instance Axis1MABIMAX100 : DTDFVocab:Component [
    base:desc "First axis of the MABI MAX 100 six‑axis industrial robot, comprising a permanent‑magnet synchronous motor, a gearwheel gearbox and a cycloidal gearbox"
]

// C16: Environment
instance IndustrialRobotLab : DTDFVocab:Environment [
    base:contains Axis1MABIMAX100, MQTTBrokerEnabler, DataProcessingEngine, SimulinkSimulationEngine, DashboardEngine
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "The digital shadow follows the Digital Shadow Reference Model: a Purpose (FrictionDerivation) links to an Asset (MABI robot first axis), multiple DataTraces (measured current I_M, reference and simulated motor/gear outputs), Processing components (Simulation_M, Simulation_GW, Simulation_GB) that execute the Simulink models, and metadata that tie each trace to its source. All elements are instantiated as concrete classes in a UML class diagram."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Each DataPoint is traceable to its originating sensor or processing component, enabling full provenance. Simulated outputs are continuously compared with measured references to validate and update friction models. Both analytical (white‑box) and data‑driven (black‑box) models are used, and the system supports continuous re‑identification to account for wear, load changes, temperature variations, and tool changes."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "Sensor data are transmitted from the robot to the digital shadow over MQTT. Asset information is encapsulated using Asset Administration Shells (AAS) to integrate with the digital shadow infrastructure."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "The implementation uses the Asset Administration Shell (AAS) standard for asset representation and SysML as a standardized modeling language, aligning with Industry 4.0 interoperability guidelines."
]
